function defaultThreadForIndex(i) {
  const preferred = ['2267','2297','2296','2583','2299','2557','2479','2292'];
  const code = preferred[i % preferred.length];
  return RA_POLY_THREADS.find(t => t.code === code) || RA_POLY_THREADS[i % RA_POLY_THREADS.length];
}

function parseDSTHeader(headerText, key) {
  const safe = key.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = new RegExp(safe + ':\\s*([^\\r\\n]+)').exec(headerText);
  return m ? m[1].trim() : '';
}

function decodeDSTMove(b0, b1, b2) {
  let dx = 0, dy = 0;

  // Correct Tajima DST bit mapping.
  // X uses low nibble of byte 0/1 plus byte 2 bits 2/3.
  if (b0 & 0x01) dx += 1;
  if (b0 & 0x02) dx -= 1;
  if (b0 & 0x04) dx += 9;
  if (b0 & 0x08) dx -= 9;
  if (b1 & 0x01) dx += 3;
  if (b1 & 0x02) dx -= 3;
  if (b1 & 0x04) dx += 27;
  if (b1 & 0x08) dx -= 27;
  if (b2 & 0x04) dx += 81;
  if (b2 & 0x08) dx -= 81;

  // Y uses high nibble of byte 0/1 plus byte 2 bits 4/5.
  if (b0 & 0x80) dy += 1;
  if (b0 & 0x40) dy -= 1;
  if (b0 & 0x20) dy += 9;
  if (b0 & 0x10) dy -= 9;
  if (b1 & 0x80) dy += 3;
  if (b1 & 0x40) dy -= 3;
  if (b1 & 0x20) dy += 27;
  if (b1 & 0x10) dy -= 27;
  if (b2 & 0x20) dy += 81;
  if (b2 & 0x10) dy -= 81;

  return { dx, dy };
}

function parseDSTArrayBuffer(buffer) {
  const bytes = new Uint8Array(buffer);
  const headerBytes = bytes.slice(0, Math.min(512, bytes.length));
  let headerText = '';
  for (let i = 0; i < headerBytes.length; i++) headerText += String.fromCharCode(headerBytes[i]);

  const headerStitches = parseInt(parseDSTHeader(headerText, 'ST'), 10);
  const headerColorChanges = parseInt(parseDSTHeader(headerText, 'CO'), 10);
  const label = parseDSTHeader(headerText, 'LA');

  let x = 0, y = 0;
  let minX = 0, minY = 0, maxX = 0, maxY = 0;
  let stitchRecords = 0;
  let jumpRecords = 0;
  let colorChanges = 0;
  let currentBlock = [];
  const blocks = [currentBlock];

  for (let i = 512; i + 2 < bytes.length; i += 3) {
    const b0 = bytes[i], b1 = bytes[i + 1], b2 = bytes[i + 2];

    // Tajima DST end command
    if (b0 === 0x00 && b1 === 0x00 && b2 === 0xF3) break;

    const mv = decodeDSTMove(b0, b1, b2);
    const x0 = x, y0 = y;
    x += mv.dx;
    y += mv.dy;

    minX = Math.min(minX, x);
    minY = Math.min(minY, y);
    maxX = Math.max(maxX, x);
    maxY = Math.max(maxY, y);

    const isColorChange = (b2 & 0xC3) === 0xC3;
    const isJump = !isColorChange && ((b2 & 0x83) === 0x83);

    if (isColorChange) {
      colorChanges++;
      currentBlock = [];
      blocks.push(currentBlock);
    } else if (isJump) {
      jumpRecords++;
    } else {
      stitchRecords++;
      currentBlock.push({ x0, y0, x1: x, y1: y });
    }
  }

  const activeBlocks = blocks.filter(b => b.length);
  const threadStops = Math.max(1, (Number.isFinite(headerColorChanges) ? headerColorChanges + 1 : colorChanges + 1));
  const widthMm = (maxX - minX) / 10;
  const heightMm = (maxY - minY) / 10;
  const widthIn = widthMm / 25.4;
  const heightIn = heightMm / 25.4;

  return {
    label,
    headerStitches: Number.isFinite(headerStitches) ? headerStitches : stitchRecords,
    parsedStitches: stitchRecords,
    jumpRecords,
    colorChanges: Number.isFinite(headerColorChanges) ? headerColorChanges : colorChanges,
    threadStops,
    widthIn,
    heightIn,
    widthMm,
    heightMm,
    minX, minY, maxX, maxY,
    blocks: activeBlocks
  };
}

function renderDSTCanvas(dst, threads) {
  const pad = 36;
  const designW = Math.max(1, dst.maxX - dst.minX);
  const designH = Math.max(1, dst.maxY - dst.minY);
  const maxSide = 1300;
  const scale = Math.min(maxSide / designW, maxSide / designH, 3);
  const W = Math.max(80, Math.round(designW * scale + pad * 2));
  const H = Math.max(80, Math.round(designH * scale + pad * 2));

  const cv = document.createElement('canvas');
  cv.width = W;
  cv.height = H;
  const ctx = cv.getContext('2d');
  ctx.clearRect(0, 0, W, H);
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  ctx.lineWidth = Math.max(2.25, scale * 0.95);

  const mapX = (v) => (v - dst.minX) * scale + pad;
  const mapY = (v) => (dst.maxY - v) * scale + pad;

  for (let i = 0; i < dst.blocks.length; i++) {
    const th = threads[i] || defaultThreadForIndex(i);
    ctx.strokeStyle = th.hex;
    ctx.beginPath();
    for (const s of dst.blocks[i]) {
      ctx.moveTo(mapX(s.x0), mapY(s.y0));
      ctx.lineTo(mapX(s.x1), mapY(s.y1));
    }
    ctx.stroke();
  }

  return cv;
}

async function openDST(entry) {
  const buffer = await entry.file.arrayBuffer();
  const dst = parseDSTArrayBuffer(buffer);
  // Guard against a malformed / non-DST file: a bad decode yields ~no stitch
  // records or no drawable segments. Fail clearly instead of placing a blank
  // or garbage stitch canvas on the shirt.
  if (!dst || !(dst.parsedStitches > 10) || !dst.blocks || !dst.blocks.length) {
    throw new Error('Could not read this DST file — no stitch data found. Re-export the Tajima .dst and try again.');
  }
  entry.kind = 'dst';
  entry.dst = dst;
  entry.dstThreads = Array.from({ length: dst.threadStops }, (_, i) => defaultThreadForIndex(i));
  entry.dstElements = Array.from({ length: dst.threadStops }, (_, i) => '');
  entry.canvas = renderDSTCanvas(dst, entry.dstThreads);
  entry.hasTransparency = true;
  entry.photographic = false;
  entry.palette = entry.dstThreads.map((t, i) => {
    const m = /^#?([0-9a-f]{6})$/i.exec(t.hex);
    const n = m ? parseInt(m[1], 16) : 0;
    return {
      r: (n >> 16) & 255,
      g: (n >> 8) & 255,
      b: n & 255,
      hex: t.hex.toUpperCase(),
      pct: Math.max(1, Math.round(100 / Math.max(1, dst.threadStops))),
      threadCode: t.code,
      threadName: t.name,
      threadIndex: i
    };
  });
  entry.info = {
    Type: 'Embroidery DST',
    'Exact stitch count': dst.headerStitches.toLocaleString(),
    'Parsed stitch records': dst.parsedStitches.toLocaleString(),
    'Color changes': dst.colorChanges,
    'Thread stops': dst.threadStops,
    'Design size': dst.widthIn.toFixed(2) + '" × ' + dst.heightIn.toFixed(2) + '"',
    'Design size mm': dst.widthMm.toFixed(1) + ' × ' + dst.heightMm.toFixed(1) + ' mm'
  };
  if (!entry.printW || entry.printW === 12) entry.printW = Math.min(12, Math.max(2, +dst.widthIn.toFixed(2)));
  makeThumb(entry, entry.canvas);
}

function updateDSTThreadColor(entryId, stopIndex, threadIndex) {
  const entry = entries.find(e => e.id === entryId);
  if (!entry || entry.kind !== 'dst') return;
  const th = RA_POLY_THREADS[Number(threadIndex)] || defaultThreadForIndex(stopIndex);
  entry.dstThreads[stopIndex] = th;
  entry.canvas = renderDSTCanvas(entry.dst, entry.dstThreads);
  entry.palette = entry.dstThreads.map((t, i) => {
    const m = /^#?([0-9a-f]{6})$/i.exec(t.hex);
    const n = m ? parseInt(m[1], 16) : 0;
    return {
      r: (n >> 16) & 255,
      g: (n >> 8) & 255,
      b: n & 255,
      hex: t.hex.toUpperCase(),
      pct: Math.max(1, Math.round(100 / Math.max(1, entry.dstThreads.length))),
      threadCode: t.code,
      threadName: t.name,
      threadIndex: i
    };
  });
  entry._trimmedArt = null;
  entry.mockCanvas = null;
  entry.view.fitted = false;
  entry.mockOn = true;
  makeThumb(entry, entry.canvas);
  rebuildMockup(entry);
  refreshStage(entry);
  renderInfo(entry);
  updatePrintAdvisor(entry);
  updateEmbroideryAdvisor(entry);
  renderThreadColorsButtonState();
  if ($('threadColorsModal') && $('threadColorsModal').classList.contains('visible')) renderThreadColorsModal(entry);
  if ($('artDetailsModal') && $('artDetailsModal').classList.contains('visible')) openArtDetails();
  showToast('Thread color updated on the shirt mockup');
}

function updateDSTThreadElement(entryId, stopIndex, value) {
  const entry = entries.find(e => e.id === entryId);
  if (!entry || entry.kind !== 'dst') return;
  if (!Array.isArray(entry.dstElements)) entry.dstElements = [];
  entry.dstElements[stopIndex] = (value || '').trim();
  renderInfo(entry);
  updateEmbroideryAdvisor(entry);
  if ($('threadColorsModal') && $('threadColorsModal').classList.contains('visible')) renderThreadColorsModal(entry);
  if ($('artDetailsModal') && $('artDetailsModal').classList.contains('visible')) openArtDetails();
}


function dstElementName(entry, i) {
  if (!entry) return '';
  if (!Array.isArray(entry.dstElements)) entry.dstElements = [];
  return (entry.dstElements[i] || '').trim();
}

function dstThreadAssignment(entry, i) {
  const t = (entry && entry.dstThreads && entry.dstThreads[i]) ? entry.dstThreads[i] : defaultThreadForIndex(i);
  const element = dstElementName(entry, i);
  return {
    stop: i + 1,
    element,
    code: t.code,
    name: t.name,
    hex: t.hex
  };
}

function dstThreadSummaryArray(entry) {
  if (!entry || entry.kind !== 'dst' || !entry.dstThreads) return [];
  return entry.dstThreads.map((t, i) => {
    const a = dstThreadAssignment(entry, i);
    return 'Stop ' + a.stop + (a.element ? ' (' + a.element + ')' : '') + ': ' + a.code + ' ' + a.name;
  });
}

function dstThreadSummaryInline(entry) {
  return dstThreadSummaryArray(entry).join(' · ');
}

// Distinct from dstThreadSummaryInline (per-stop assignments WITH element names):
// this lists just the RA Poly thread colors used — so the proof can show
// "Thread colors" (the palette) vs "Thread assignments" (which stop = which) separately.
function dstThreadColorsOnly(entry) {
  if (!entry || entry.kind !== 'dst' || !entry.dstThreads) return '';
  return entry.dstThreads.map(function (t) {
    return ((t && t.code) ? t.code + ' ' : '') + ((t && t.name) ? t.name : '');
  }).filter(function (s) { return s.trim(); }).join(', ');
}

function dstThreadAssignmentsHtml(entry) {
  if (!entry || entry.kind !== 'dst' || !entry.dstThreads) return '';
  let html = '<div class="dst-thread-assignment-list"><b>Thread assignments</b>';
  entry.dstThreads.forEach((t, i) => {
    const a = dstThreadAssignment(entry, i);
    html += '<div class="row">Stop ' + a.stop + (a.element ? ' — <b>' + escapeHtml(a.element) + '</b>' : '') + ': '
      + escapeHtml(a.code + ' ' + a.name) + ' <span style="color:#6b7a68">(' + escapeHtml(a.hex.toUpperCase()) + ')</span></div>';
  });
  html += '</div>';
  return html;
}

function renderThreadColorsButtonState() {
  const btn = $('threadColorsBtn');
  if (!btn) return;
  const e = current();
  const enabled = !!(e && e.status === 'ready' && e.kind === 'dst' && e.dst);
  btn.classList.toggle('disabled', !enabled);
  btn.title = enabled
    ? 'Choose Robison-Anton Poly thread colors for this DST file'
    : 'Upload or open a DST file to choose thread colors';
}

function closeThreadColors() {
  const modal = $('threadColorsModal');
  if (modal) modal.classList.remove('visible');
}

function renderThreadColorsModal(entry) {
  const body = $('threadColorsBody');
  const summary = $('threadColorsSummary');
  const selected = $('threadColorsSelected');
  if (!body || !summary || !selected) return;

  summary.innerHTML =
    '<div class="sum"><b>File</b><span>' + escapeHtml(entry.name || 'DST file') + '</span></div>' +
    '<div class="sum"><b>Exact stitches</b><span>' + escapeHtml(estimateEmbroidery(entry).stitchesText) + '</span></div>' +
    '<div class="sum"><b>Thread stops</b><span>' + escapeHtml(String(entry.dst.threadStops)) + '</span></div>' +
    '<div class="sum"><b>Design size</b><span>' + escapeHtml(entry.dst.widthIn.toFixed(2) + '" × ' + entry.dst.heightIn.toFixed(2) + '"') + '</span></div>';

  body.innerHTML = dstThreadSelectorHtml(entry, true);
  selected.innerHTML = '<b>Selected thread names and elements:</b><br>' + escapeHtml(dstThreadSummaryInline(entry) || 'No thread stops found.') + dstThreadAssignmentsHtml(entry);
}

function openThreadColors() {
  const e = current();
  if (!e || e.status !== 'ready' || e.kind !== 'dst' || !e.dst) {
    showToast('Open a DST file first');
    renderThreadColorsButtonState();
    return;
  }
  renderThreadColorsModal(e);
  const modal = $('threadColorsModal');
  if (modal) modal.classList.add('visible');
}

window.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') {
    const modal = $('threadColorsModal');
    if (modal && modal.classList.contains('visible')) closeThreadColors();
  }
});



function dstThreadSelectorHtml(entry, modalMode) {
  if (!entry || entry.kind !== 'dst' || !entry.dst) return '';
  let html = '<div class="method-row"><strong>Robison-Anton Poly thread colors:</strong><br>Choose screen-preview thread colors for each DST color stop. You can also label what each stop runs, such as outline, fill, text, or accent.</div>';
  html += '<div class="dst-thread-grid' + (modalMode ? ' modal' : '') + '">';
  for (let i = 0; i < entry.dst.threadStops; i++) {
    const cur = entry.dstThreads[i] || defaultThreadForIndex(i);
    const element = dstElementName(entry, i);
    let opts = '';
    for (let j = 0; j < RA_POLY_THREADS.length; j++) {
      const t = RA_POLY_THREADS[j];
      const selected = (t.code === cur.code && t.name === cur.name) ? ' selected' : '';
      opts += '<option value="' + j + '"' + selected + '>' + t.code + ' · ' + escapeHtml(t.name) + '</option>';
    }
    html += '<div class="dst-thread-row">'
      + '<span class="dst-thread-swatch" style="background:' + cur.hex + '"></span>'
      + '<span class="dst-thread-stop">Stop ' + (i + 1) + '</span>'
      + '<div><select onchange="updateDSTThreadColor(' + entry.id + ',' + i + ',this.value)">' + opts + '</select>'
      + '<div class="dst-thread-name">' + escapeHtml(cur.code + ' · ' + cur.name) + '</div></div>'
      + '<div class="dst-thread-element-wrap">'
      + '<span class="dst-thread-element-label">Element / run</span>'
      + '<input class="dst-thread-element-input" value="' + escapeHtml(element) + '" placeholder="outline, fill, text, accent…" oninput="updateDSTThreadElement(' + entry.id + ',' + i + ',this.value)">'
      + '</div>'
      + '<span class="dst-pill">' + escapeHtml(cur.hex.toUpperCase()) + '</span>'
      + '</div>';
  }
  html += '</div>';
  return html;
}



