    const KK = e.mockOn ? (PHOTO._K || 1) : 1;
    e.artDX = artDrag.dx + dir * (ev.clientX - artDrag.sx) / (e.view.z * KK);
    e.artDY = artDrag.dy + (ev.clientY - artDrag.sy) / (e.view.z * KK);
    if ((e.printLoc || 'Full Front') !== 'Left Chest' && Math.abs(e.artDX) < 8) e.artDX = 0;  // snap to center
    // dragging across the gap moves the print to the other shirt
