// Keyboard shortcuts
window.addEventListener('keydown', (ev) => {
  if (!currentCanvas()) return;
  // Don't hijack typing/navigation inside editable or form controls — arrow keys
  // must move the caret in #txt-text / #custMessage and change <select> options,
  // and Delete must delete text, not remove the art from the shirt.
  const t = ev.target;
  if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.tagName === 'SELECT' || t.isContentEditable)) return;
  const ke = current();
  if (ke && ke.mockOn && ke.artSel && ke.onShirt !== false) {
    const step = ev.shiftKey ? 10 : 2;
    let used = true;
    if (ev.key === 'ArrowLeft') ke.artDX = (ke.artDX || 0) - step;
    else if (ev.key === 'ArrowRight') ke.artDX = (ke.artDX || 0) + step;
    else if (ev.key === 'ArrowUp') ke.artDY = (ke.artDY || 0) - step;
    else if (ev.key === 'ArrowDown') ke.artDY = (ke.artDY || 0) + step;
    else if (ev.key === 'Delete') { ke.onShirt = false; renderInfo(ke); }
    else used = false;
    if (used) { ev.preventDefault(); rebuildMockup(ke); return; }
  }
  if (ev.key === '+' || ev.key === '=') zoomBy(1.25);
  else if (ev.key === '-') zoomBy(0.8);
  else if (ev.key === '0') zoomFit();
  else if (ev.key === '1') zoom100();
  else if (ev.key === 'ArrowRight') changePage(1);
  else if (ev.key === 'ArrowLeft') changePage(-1);
});

