// Blank front+back preview shown before any art is opened
function repaintLanding() {
  const cv = $('landingPreview');
  if (!cv || PHOTO.state !== 'ready' || !PHOTO.frames.length) return;
  const F0 = PHOTO.frames[0];
  const FB = PHOTO.frames[backFrameIdx()];
  const TH = 460;
  const s0 = TH / F0.H, sB = TH / FB.H, gap = 26;
  cv.width = Math.round(F0.W * s0 + gap + FB.W * sB);
  cv.height = TH;
  const ctx = cv.getContext('2d');
  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = 'high';
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, cv.width, cv.height);
  ctx.drawImage(recolorFrame(F0, currentGarment), 0, 0, Math.round(F0.W * s0), TH);
  ctx.drawImage(recolorFrame(FB, currentGarment), Math.round(F0.W * s0) + gap, 0, Math.round(FB.W * sB), TH);
}
