function sampleAt(clientX, clientY) {
  const e = current();
  const canvas = currentCanvas();
  if (!e || !canvas) return;
  const r = stage.getBoundingClientRect();
  const cx = Math.floor((clientX - r.left - e.view.tx) / e.view.z);
  const cy = Math.floor((clientY - r.top - e.view.ty) / e.view.z);
  if (cx < 0 || cy < 0 || cx >= canvas.width || cy >= canvas.height) return;
  const px = canvas.getContext('2d').getImageData(cx, cy, 1, 1).data;
  if (px[3] === 0) { showToast('Transparent pixel'); return; }
  const hex = '#' + [px[0], px[1], px[2]].map(n => n.toString(16).padStart(2, '0')).join('').toUpperCase();
  $('eyeDot').style.background = hex;
  $('eyeHex').textContent = hex;
  $('eyeChip').classList.add('visible');
  copyText(hex);
}
