/* ============================================================
   Palette & print-readiness analysis
   ============================================================ */
function analyzeEntry(entry) {
  if (entry.kind === 'dst') {
    updateFileAdviceBadges(entry);
    return;
  }
  const canvas = analysisCanvas(entry);
  if (!canvas || !canvas.width) return;
  // Downsample for speed
  const s = Math.min(96 / canvas.width, 96 / canvas.height, 1);
  const w = Math.max(1, Math.round(canvas.width * s));
  const h = Math.max(1, Math.round(canvas.height * s));
  const off = document.createElement('canvas');
  off.width = w; off.height = h;
  const ctx = off.getContext('2d', { willReadFrequently: true });
  ctx.drawImage(canvas, 0, 0, w, h);
  const data = ctx.getImageData(0, 0, w, h).data;
  const res = computePaletteFromData(data, { skipWhite: entry.kind === 'pdf' });
  entry.palette = res.colors;
  entry.photographic = res.photographic;
  entry.hasTransparency = entry.kind === 'pdf' ? null : res.hasTransparency;
  if (!entry.printW) {
    entry.printW = entry.dpi ? Math.min(60, Math.max(0.5, +(canvas.width / entry.dpi).toFixed(1))) : 10;
  }
  updateFileAdviceBadges(entry);
}

// Pure function: quantize RGBA pixel data into dominant spot colors (up to 12)
function computePaletteFromData(data, opts) {
  const skipWhite = !!(opts && opts.skipWhite);
  const bins = new Map();
  let hasTransparency = false;
  let counted = 0;
  for (let i = 0; i < data.length; i += 4) {
    const a = data[i + 3];
    if (a < 250) hasTransparency = true;
    if (a < 128) continue;
    const r = data[i], g = data[i + 1], b = data[i + 2];
    if (skipWhite && r >= 245 && g >= 245 && b >= 245) continue;
    counted++;
    const key = ((r >> 4) << 8) | ((g >> 4) << 4) | (b >> 4);
    let bin = bins.get(key);
    if (!bin) { bin = { n: 0, r: 0, g: 0, b: 0 }; bins.set(key, bin); }
    bin.n++; bin.r += r; bin.g += g; bin.b += b;
  }
  const sorted = [...bins.values()].sort((x, y) => y.n - x.n);
  const picked = [];
  for (const bin of sorted) {
    if (picked.length >= 12) break;
    const r = Math.round(bin.r / bin.n), g = Math.round(bin.g / bin.n), b = Math.round(bin.b / bin.n);
    let dup = false;
    for (const p of picked) {
      if (Math.hypot(p.r - r, p.g - g, p.b - b) < 36) { p.n += bin.n; dup = true; break; }
    }
    if (!dup) picked.push({ r, g, b, n: bin.n });
  }
  const significant = picked.filter(p => counted && (p.n / counted) >= 0.01);
  const colors = significant.map(p => ({
    r: p.r, g: p.g, b: p.b,
    hex: '#' + [p.r, p.g, p.b].map(n => n.toString(16).padStart(2, '0')).join('').toUpperCase(),
    pct: Math.max(1, Math.round((p.n / counted) * 100))
  }));
  // Lots of distinct blended clusters = gradients/photo art rather than flat spot colors
  const halfPct = picked.filter(p => counted && (p.n / counted) >= 0.005).length;
  const photographic = halfPct > 8;
  return { colors, hasTransparency, photographic };
}

