  ['Green C', 0, 171, 132], ['347 C', 0, 154, 68], ['348 C', 0, 132, 61], ['349 C', 4, 106, 56],
  ['343 C', 17, 87, 64], ['354 C', 0, 177, 64], ['355 C', 0, 150, 57], ['361 C', 67, 176, 42],
  ['368 C', 120, 190, 32], ['375 C', 151, 215, 0], ['382 C', 196, 214, 0], ['584 C', 210, 215, 85],
  ['576 C', 120, 157, 74], ['5747 C', 61, 68, 30],
  ['7499 C', 241, 230, 178], ['4525 C', 207, 196, 147], ['468 C', 221, 203, 164],
  ['871 C (gold)', 132, 117, 78], ['7505 C', 129, 96, 64], ['469 C', 105, 63, 35],
  ['476 C', 78, 54, 41], ['4625 C', 79, 44, 29],
  ['Cool Gray 1 C', 217, 217, 214], ['Cool Gray 3 C', 200, 201, 199], ['Cool Gray 5 C', 177, 179, 179],
  ['Cool Gray 7 C', 151, 153, 155], ['Cool Gray 9 C', 117, 120, 123], ['Cool Gray 11 C', 83, 86, 90],
  ['425 C', 84, 88, 90], ['432 C', 51, 63, 72], ['446 C', 63, 68, 68], ['447 C', 55, 58, 54],
  ['Warm Gray 1 C', 215, 210, 203], ['Warm Gray 7 C', 150, 140, 131],
  ['Black C', 45, 41, 38], ['Black 6 C', 16, 24, 32]
