  if (e.mockOn && e.mockCanvas) {
    const clean = getCleanMock(e);
    const s = Math.min(1100 / clean.width, 1);
    const t = document.createElement('canvas');
    t.width = Math.round(clean.width * s);
    t.height = Math.round(clean.height * s);
    t.getContext('2d').drawImage(clean, 0, 0, t.width, t.height);
    mock = t.toDataURL('image/png');
  }

  let rows = '';
  let artCards = '';
  let artCount = 0;

  for (const x of mockEntries()) {
    const sides = x.printBoth ? 'Front & Back' : (sideOf(x) === 'back' ? 'Back' : 'Front');
    const loc = x.printLoc || (sideOf(x) === 'back' ? 'Full Back' : 'Full Front');
    const thumb = proofArtThumbDataUrl(x);
    const widthTxt = (x.printW || 10) + '" wide';
    const offsetTxt = 'X ' + Math.round(x.artDX || 0) + ' / Y ' + Math.round(x.artDY || 0);

    rows += '<tr><td>' + escapeHtml(sides) + '</td><td>' + escapeHtml(x.name) + '</td><td>'
      + widthTxt + ' · ' + escapeHtml(loc) + ' · ' + offsetTxt + (x.kind === 'dst' ? ' · ' + escapeHtml(dstThreadSummaryInline(x)) : '') + '</td></tr>';

    if (thumb) {
      artCount++;
      artCards += '<div class="proof-art-card">'
        + '<h3>Artwork ' + artCount + ': ' + escapeHtml(sides) + '</h3>'
        + '<img src="' + thumb + '" alt="Artwork preview">'
        + '<div class="meta"><b>File:</b> ' + escapeHtml(x.name) + '<br>'
        + '<b>Placement:</b> ' + escapeHtml(loc) + '<br>'
        + '<b>Print size:</b> ' + escapeHtml(widthTxt) + '<br>'
        + '<b>Position:</b> ' + escapeHtml(offsetTxt) + (x.kind === 'dst' ? '<br><b>Thread colors:</b> ' + escapeHtml(dstThreadColorsOnly(x)) + '<br><b>Thread assignments:</b> ' + escapeHtml(dstThreadSummaryInline(x)) : '') + '</div>'
        + '</div>';
    }
  }

  $('specSheet').innerHTML =
    '<div class="sp-head">'
    + '<div><h1>Mockup Proof</h1><div class="sp-sub">Northwest Custom Apparel — ' + today + '</div></div>'
    + '<div class="sp-sub" style="text-align:right">' + escapeHtml(CONTACT_EMAIL) + '</div>'
    + '</div>'
    + '<div class="proof-upgrade-note"><b>Recommended print method:</b> ' + escapeHtml(printAdvice(e).method) + ' — ' + escapeHtml(printAdvice(e).copy) + '</div>'
    + '<div class="proof-upgrade-note"><b>' + (e.kind === 'dst' ? 'Exact DST embroidery:' : 'Embroidery estimate:') + '</b> ' + escapeHtml(estimateEmbroidery(e).stitchesText) + ' stitches · ' + escapeHtml(estimateEmbroidery(e).threadText) + '. ' + escapeHtml(estimateEmbroidery(e).copy) + '</div>'
    + (e.kind === 'dst' ? '<div class="proof-upgrade-note"><b>Selected thread colors and elements:</b> ' + escapeHtml(dstThreadSummaryInline(e)) + '</div>' : '')
    + '<div class="proof-upgrade-note"><b>Please review carefully before approval.</b><br>'
    + 'Confirm shirt color, artwork, spelling, size, location, and front/back placement. Screen colors are approximate.</div>'
    + '<div class="proof-upgrade-note">Mockup shown on a Port &amp; Company PC61 crew tee for color and placement reference; your ordered garment style may differ.</div>'
    + '<div class="sp-grid">'
    + '<div><b>Garment:</b> Port &amp; Company PC61 Essential Tee</div>'
    + '<div><b>Color:</b> ' + escapeHtml(garment) + '</div>'
    + '<div><b>Proof type:</b> Customer approval mockup</div>'
    + '<div><b>Artwork files:</b> ' + artCount + '</div>'
    + '</div>'
    + (mock ? '<p style="text-align:center"><img src="' + mock + '" style="max-width:100%;max-height:520px;border:1px solid #ddd;border-radius:8px"></p>' : '')
    + (artCards ? '<h2 style="font-size:15px;color:#2f661e;margin:10px 0 8px;">Artwork submitted</h2><div class="proof-art-grid">' + artCards + '</div>' : '')
    + (e.kind === 'dst' ? '<h2 style="font-size:15px;color:#2f661e;margin:10px 0 8px;">Embroidery thread assignments</h2><div class="proof-upgrade-note">' + escapeHtml(dstThreadSummaryInline(e)) + '</div>' : '')
    + (rows ? '<table><tr><th>Side</th><th>Artwork file</th><th>Print size &amp; placement</th></tr>' + rows + '</table>' : '')
    + '<div class="approval-checklist"><b>Approval checklist</b><br>'
    + '☐ Shirt color is correct<br>'
    + '☐ Front artwork and placement are correct<br>'
