function buildSpecSheet(e) {
  const today = new Date().toLocaleDateString();
  const g = garmentState();
  const garmentLabel = currentGarment === 'checker' ? 'Not selected'
    : (currentGarmentName ? currentGarmentName + ' (' + currentGarment + ')' : currentGarment);
  const n = e.palette ? e.palette.length : 0;
  const screens = n + (g === 'dark' ? 1 : 0);

  // Thumbnail of whatever is being viewed (art, separation, or mockup)
  let thumb = '';
  const src = (e.mockOn && e.mockCanvas) ? getCleanMock(e) : currentCanvas();
  if (src) {
    const s = Math.min(640 / src.width, 640 / src.height, 1);
    const t = document.createElement('canvas');
    t.width = Math.max(1, Math.round(src.width * s));
    t.height = Math.max(1, Math.round(src.height * s));
    t.getContext('2d').drawImage(src, 0, 0, t.width, t.height);
    thumb = t.toDataURL('image/png');
  }

  let inkRows = '';
  if (e.palette) {
    e.palette.forEach((c, i) => {
      const pms = nearestPMS(c.r, c.g, c.b);
      inkRows += '<tr><td>' + (i + 1) + '</td>'
        + '<td><span class="sp-swatch" style="background:' + c.hex + '"></span>' + c.hex + '</td>'
        + '<td>' + escapeHtml(pms.close ? 'PMS ' + pms.name + ' (approx.)' : 'No close PMS match') + '</td>'
        + '<td>' + c.pct + '%</td></tr>';
    });
  }

  const flags = [];
  if (g === 'dark') flags.push('Dark garment — white underbase included in screen count.');
  if (g === 'light') flags.push('Light garment — no underbase needed.');
  if (e.photographic) flags.push('Gradient/photographic art — likely simulated process or DTG, not spot color.');
  if (e.hasTransparency === true) flags.push('Art has a transparent background.');
  if (e.hasTransparency === false) flags.push('No transparency — background prints unless removed.');
  if (e.kind === 'pdf') flags.push('Vector file — sharp at any size.');
  if (e.ext === 'cdr') flags.push('CDR embedded preview only — confirm art from source file.');
  if (e.dpi) flags.push('Saved at ' + e.dpi + ' DPI.');
  if (e.kind === 'canvas' && e.canvas && e.printW) {
    flags.push('Effective resolution at ' + e.printW + '" wide: ' + Math.round(e.canvas.width / e.printW) + ' DPI.');
  }

  $('specSheet').innerHTML =
    '<div class="sp-head">'
    + '<div><h1>Art Spec Sheet</h1><div class="sp-sub">Northwest Custom Apparel — prepared ' + today + '</div></div>'
    + '<div class="sp-sub" style="text-align:right">' + escapeHtml(CONTACT_EMAIL) + '</div>'
    + '</div>'
    + '<div class="sp-grid">'
    + '<div><b>File:</b> ' + escapeHtml(e.name) + '</div>'
    + '<div><b>Type:</b> ' + escapeHtml(String((e.info && e.info['Type']) || e.ext.toUpperCase())) + '</div>'
    + '<div><b>Print location:</b> ' + escapeHtml(e.printLoc || 'Not selected') + '</div>'
    + '<div><b>Print width:</b> ' + (e.printW ? e.printW + '"' : '—') + '</div>'
    + '<div><b>Garment color:</b> ' + escapeHtml(garmentLabel) + '</div>'
    + '<div><b>Quantity:</b> ' + (e.qty || '—') + '</div>'
    + '<div><b>Spot colors:</b> ' + (n || '—') + '</div>'
    + '<div><b>Screens (incl. underbase):</b> ' + (n ? screens : '—') + '</div>'
    + '</div>'
    + (inkRows ? '<table><tr><th>#</th><th>Color</th><th>Closest PMS</th><th>Coverage</th></tr>' + inkRows + '</table>' : '')
    + (flags.length ? '<div class="sp-flags"><b>Notes:</b><br>• ' + flags.map(escapeHtml).join('<br>• ') + '</div>' : '')
    + (thumb ? '<p><img class="sp-thumb" src="' + thumb + '"></p>' : '')
    + '<div class="sp-foot">All counts and PMS matches are estimates from on-screen colors, pending review by the NWCA art department. Generated by the NWCA Art File Viewer.</div>';
}

