function copyText(text) {
  const done = () => showToast('Copied ' + text);
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text).then(done, () => showToast(text));
  } else {
    showToast(text);
  }
}

let toastTimer = null;
// showToast(message) — transient feedback.
// showToast(message, { label, fn }) — sticky toast with one clickable action
// (e.g. "Undo"); stays longer and is clickable (the toast is pointer-events:none
// by default, so we flip it on while an action is present).
function showToast(msg, action) {
  let t = $('toast');
  if (!t) {
    t = document.createElement('div');
    t.id = 'toast';
    t.setAttribute('role', 'status');        // announce to screen readers
    t.setAttribute('aria-live', 'polite');
    document.body.appendChild(t);
  }
  const hasAction = !!(action && action.label && typeof action.fn === 'function');
  t.innerHTML = '';
  const span = document.createElement('span');
  span.textContent = msg;                      // textContent — never inject markup
  t.appendChild(span);
  if (hasAction) {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'toast-action';
    btn.textContent = action.label;
    btn.addEventListener('click', () => {
      t.classList.remove('show');
      try { action.fn(); } catch (e) { /* non-fatal */ }
    });
    t.appendChild(btn);
  }
  t.classList.toggle('has-action', hasAction);
  t.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => t.classList.remove('show'), hasAction ? 6000 : 1800);
}

/* ============================================================
   PNG export
   ============================================================ */
async function downloadPNG() {
  const e = current();
  if (!e || e.status !== 'ready') return;
  let canvas;
  let suffix = (e.kind === 'pdf' && e.pageCount > 1) ? '_page' + e.pageNum : '';
  if (e.mockOn && e.mockCanvas) {
    // export the mockup on its studio backdrop, without the selection box
    const clean = getCleanMock(e);
    canvas = document.createElement('canvas');
    canvas.width = clean.width;
    canvas.height = clean.height;
    const octx = canvas.getContext('2d');
    octx.fillStyle = '#eef0f2';
    octx.fillRect(0, 0, canvas.width, canvas.height);
    octx.drawImage(clean, 0, 0);
    suffix += '_mockup';
  } else if (e.sepIndex != null && e.sepCanvas) {
    canvas = e.sepCanvas;                                         // the separation being viewed
    suffix += '_screen' + (e.sepIndex + 1) + '_' + e.palette[e.sepIndex].hex.slice(1);
  } else if (e.knockOn && e.kind === 'canvas') {
    canvas = getKnockedArt(e) || e.canvas;                        // transparent-background PNG
    suffix += '_transparent';
  } else if (e.kind === 'pdf') {
    $('dlBtn').disabled = true;
    try { canvas = await renderPdfPage(e, true); }
    finally { $('dlBtn').disabled = false; }
  } else {
    canvas = e.canvas;
  }
  if (!canvas) return;
  const base = e.name.replace(/\.[^.]+$/, '');
  canvas.toBlob((blob) => {
    if (!blob) return;
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = base + suffix + '.png';
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 1500);
  }, 'image/png');
}

/* ============================================================
   Helpers
   ============================================================ */
function fmtSize(b) {
  if (b < 1024) return b + ' B';
  if (b < 1048576) return (b / 1024).toFixed(1) + ' KB';
  return (b / 1048576).toFixed(2) + ' MB';
}
function escapeHtml(s) {
  return s.replace(/[&<>"']/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
}

// Show info panel by default on wide screens
// Advisor panel is always available; on narrow screens it stacks below the stage
// (see responsive CSS) instead of being hidden, so it doesn't get frozen-off at
// a small page-load width.
$('infoPanel').classList.add('visible');

// ── Art-request pre-seed ──────────────────────────────────────────────────
// Lets the designer be opened straight from an art request, pre-configured:
//   /pages/garment-designer.html?color=%23c8102e&garmentName=Red&placement=Left%20Chest&company=Acme&designId=52994
// Sets the shirt color immediately, stashes the placement so the rep's next
// upload lands there, and shows a context banner. Placement strings match the
// designer's own set (Left Chest / Full Front / Upper Back / Full Back).
window.__artRequestSeed = null;
// Resolve a garment COLOR NAME (e.g. "Navy") to a hex via the designer's own
// color tables — an art request stores color NAMES, not hex.
function resolveGarmentHex(name) {
  if (!name) return '';
  const n = String(name).trim().toLowerCase();
  const pools = [typeof PC61_COLORS !== 'undefined' ? PC61_COLORS : [], typeof GARMENT_COLORS !== 'undefined' ? GARMENT_COLORS : []];
  for (const pool of pools) for (const pair of pool) {
    if (pair[0] && pair[0].toLowerCase() === n && pair[1] && pair[1] !== 'checker') return pair[1];
  }
  for (const pool of pools) for (const pair of pool) {
    if (pair[1] && pair[1] !== 'checker' && pair[0] && (pair[0].toLowerCase().indexOf(n) > -1 || n.indexOf(pair[0].toLowerCase()) > -1)) return pair[1];
  }
  return '';
}
function applyUrlPreseed() {
  let p;
  try { p = new URLSearchParams(window.location.search); } catch (e) { return; }
  const color = (p.get('color') || p.get('garmentColor') || '').trim();
  const garmentName = (p.get('garmentName') || p.get('colorName') || '').trim();
  const placement = (p.get('placement') || '').trim();
  const company = (p.get('company') || '').trim();
  const designId = (p.get('designId') || p.get('id_design') || '').trim();
  if (!color && !placement && !company && !designId) return;

  window.__artRequestSeed = { color, garmentName, placement, company, designId };

  // Garment color — immediate. setStageBg sets currentGarment; the shirt repaints
  // with it now (if loaded) and again when initPhotoMock's photos finish.
  if (color) {
    let hex = '';
    if (/^#?[0-9a-fA-F]{6}$/.test(color)) hex = color.charAt(0) === '#' ? color : '#' + color;
    else hex = resolveGarmentHex(color) || resolveGarmentHex(garmentName);
    if (hex) { try { setStageBg(hex, null, garmentName || color); } catch (e) {} }
  }

  const KNOWN = ['Left Chest', 'Full Front', 'Upper Back', 'Full Back'];
  const seedLoc = KNOWN.indexOf(placement) > -1 ? placement : '';
  renderSeedBanner({ company, designId, garmentName, color, seedLoc });

  // Reveal the "Save to Art Request" button only when opened from a real request.
  if (designId) {
    const sb = document.getElementById('saveReqBtn');
    if (sb) sb.style.display = 'inline-flex';
  }
}

// "Upload artwork for this request" — set the seeded placement, then open the
// file picker (a user gesture, so the browser allows it). The file-add handler
// applies pendingPlacement to the new entry.
function seedUpload(loc) {
  if (loc) {
    pendingSide = (loc === 'Full Back' || loc === 'Upper Back') ? 'back' : 'front';
    pendingPlacement = loc;
  }
  const fi = document.getElementById('fileInput');
  if (fi) fi.click();
}

function renderSeedBanner(seed) {
  const viewer = document.getElementById('viewerCol');
  if (!viewer || document.getElementById('seedBanner')) return;
  const esc = (s) => escapeHtml(String(s == null ? '' : s));
  const bits = [];
  if (seed.company) bits.push('<b>' + esc(seed.company) + '</b>');
  if (seed.designId) bits.push('Design #' + esc(seed.designId));
  if (seed.garmentName || seed.color) bits.push(esc(seed.garmentName || seed.color));
  if (seed.seedLoc) bits.push(esc(seed.seedLoc));
  const banner = document.createElement('div');
  banner.id = 'seedBanner';
  banner.className = 'seed-banner';
  banner.innerHTML =
    '<div class="seed-banner-text"><span class="seed-banner-icon">🧵</span>Building a mockup for ' + bits.join(' · ') + '</div>'
    + '<button type="button" class="seed-banner-btn" id="seedUploadBtn">⬆ Upload artwork for this request</button>';
  viewer.insertBefore(banner, viewer.firstChild);
  const btn = document.getElementById('seedUploadBtn');
  if (btn) btn.addEventListener('click', function () { seedUpload(seed.seedLoc); });
}

// ── Save to Art Request (rep reference mockup) ────────────────────────────
// When the designer was opened from an art request (?designId=…), this uploads
// the current clean mockup PNG to Caspio and attaches it to that request as a
// REFERENCE for Steve (he still owns the production proof). It never touches the
// Box mockup slots, the customer's File_Upload slots, or Approval_Status.
// Per Never-Break Rule 6: take the proxy host from APP_CONFIG (config/app.config.js,
// loaded in the page <head>); the literal is only a fallback if config is absent.
const ART_PROXY_BASE = (window.APP_CONFIG && window.APP_CONFIG.API && window.APP_CONFIG.API.BASE_URL)
  || 'https://caspio-pricing-proxy-ab30a049961a.herokuapp.com';

async function saveToArtRequest() {
  const seed = window.__artRequestSeed;
  if (!seed || !seed.designId) { showToast('Open this from an art request to save'); return; }

  const e = current();
  if (!e || e.status !== 'ready' || !e.mockOn || !e.mockCanvas) {
    showToast('Add artwork and build a mockup first'); return;
  }

  const btn = document.getElementById('saveReqBtn');
  const orig = btn ? btn.innerHTML : '';
  if (btn) { btn.disabled = true; btn.innerHTML = '⏳ Saving…'; }

  try {
    // 1. Clean mockup PNG (no selection chrome) → Blob.
    const clean = getCleanMock(e);
    const blob = await new Promise((res, rej) => {
      try { clean.toBlob(b => b ? res(b) : rej(new Error('Could not render mockup')), 'image/png'); }
      catch (err) { rej(err); }
    });

    // 2. Upload to the Caspio Artwork folder. Filename carries the design # +
    //    a timestamp so repeated saves never collide.
    const fd = new FormData();
    fd.append('file', blob, 'rep-mockup-' + seed.designId + '-' + Date.now() + '.png');
    const upResp = await fetchWithTimeout(ART_PROXY_BASE + '/api/files/upload', { method: 'POST', body: fd }, 45000);
    const up = await upResp.json().catch(() => ({}));
    if (!upResp.ok || !up.success || !up.externalKey) {
      throw new Error(up.error || ('Upload failed (' + upResp.status + ')'));
    }
    // Displayable URL: GET /api/files/:externalKey streams the image with its
    // content-type, so an <img src> resolves directly (no CDN formula needed).
    const imageUrl = ART_PROXY_BASE + '/api/files/' + up.externalKey;

    // 3. Build the reference metadata (garment / placement / threads / date).
    const isDst = e.kind === 'dst' && Array.isArray(e.dstThreads);
    const threads = isDst ? e.dstThreads.map((t, i) => ({
      code: t && t.code ? String(t.code) : '',
      name: t && t.name ? String(t.name) : '',
      element: (e.dstElements && e.dstElements[i]) ? String(e.dstElements[i]) : ''
    })) : [];
    let threadSummary = '';
    try { if (isDst && typeof dstThreadSummaryInline === 'function') threadSummary = dstThreadSummaryInline(e) || ''; } catch (_) {}

    const meta = {
      source: 'shirt-designer',
      designId: seed.designId,
      date: new Date().toISOString(),
      garmentColor: (typeof currentGarment !== 'undefined' && currentGarment !== 'checker') ? currentGarment : '',
      garmentName: (typeof currentGarmentName !== 'undefined' ? currentGarmentName : '') || seed.garmentName || '',
      placement: e.printLoc || seed.placement || '',
      printWidthIn: e.printW || null,
      kind: e.kind || '',
      threadSummary: threadSummary,
      threads: threads
    };

    // 4. Attach to the request (whitelisted fields only — reference, not a proof).
    const putResp = await fetchWithTimeout(ART_PROXY_BASE + '/api/art-requests/' + encodeURIComponent(seed.designId) + '/fields', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ Rep_Mockup: imageUrl, Rep_Mockup_Meta: JSON.stringify(meta) })
    }, 20000);
    if (!putResp.ok) {
      const pe = await putResp.json().catch(() => ({}));
      throw new Error(pe.error || ('Save failed (' + putResp.status + ')'));
    }

    showToast('✓ Saved to art request #' + seed.designId + ' — Steve will see it as a reference');

    // Tell the opener (the art-request detail tab) to refresh so the card shows.
    try {
      if (window.opener && !window.opener.closed) {
        window.opener.postMessage({ type: 'rep-mockup-saved', designId: seed.designId }, location.origin);
      }
    } catch (_) {}
  } catch (err) {
    console.error('[saveToArtRequest]', err);
    showToast('Save failed: ' + (err && err.message ? err.message : 'unknown error'));
  } finally {
    if (btn) { btn.disabled = false; btn.innerHTML = orig; }
  }
}

// ============================================================
//  Phase 2 — Send to Customer + Send to Steve
//  Two toolbar actions that connect the designer to NWCA's existing
//  customer-approval email (template_customer_mockup) and Steve's
//  art-submission form (GarmentSubmitForm). The rep mockup stays a
//  REFERENCE — Steve still produces the final production proof.
// ============================================================
const EMAILJS_SERVICE_ID = 'service_jgrave3';
const EMAILJS_PUBLIC_KEY = '4qSbDO-SQs19TbP80';
const SITE_ORIGIN = 'https://www.teamnwca.com';

// fetch with an abort timeout so a stalled upload/PUT can't hang the UI forever.
function fetchWithTimeout(url, opts, ms) {
  opts = opts || {};
  if (typeof AbortController === 'undefined') return fetch(url, opts);
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), ms || 30000);
  return fetch(url, Object.assign({}, opts, { signal: ctrl.signal }))
    .finally(() => clearTimeout(t));
}

// Accessible modal open/close: move focus into the dialog on open, return it to
// the trigger on close, and trap Tab within the dialog while it's open.
let _dsLastFocus = null;
function _dsFocusables(m) {
  return Array.prototype.filter.call(
    m.querySelectorAll('input, select, textarea, button, a[href], [tabindex]:not([tabindex="-1"])'),
    function (el) { return el.offsetParent !== null && !el.disabled; });
}
function dsModalOpen(id) {
  const m = document.getElementById(id);
  if (!m) return;
  _dsLastFocus = document.activeElement;
  m.classList.add('open');
  const f = _dsFocusables(m)[0];
  if (f) { try { f.focus(); } catch (e) { /* non-fatal */ } }
}
function dsModalClose(id) {
  const m = document.getElementById(id);
  if (!m) return;
  m.classList.remove('open');
  if (_dsLastFocus && typeof _dsLastFocus.focus === 'function') {
    try { _dsLastFocus.focus(); } catch (e) { /* non-fatal */ }
    _dsLastFocus = null;
  }
}
// Tab-trap for the overlay modals (Steve / Customer). The docked text panel is
// non-modal (the shirt stays interactive) so it is intentionally not trapped.
document.addEventListener('keydown', function (ev) {
  if (ev.key !== 'Tab') return;
  const m = document.querySelector('.ds-modal-overlay.open');
  if (!m) return;
  const list = _dsFocusables(m);
  if (!list.length) return;
  const first = list[0], last = list[list.length - 1];
  if (ev.shiftKey && document.activeElement === first) { ev.preventDefault(); last.focus(); }
  else if (!ev.shiftKey && document.activeElement === last) { ev.preventDefault(); first.focus(); }
});

// Both send actions need a built mockup. Returns the active entry or null (+toast).
function requireMockup() {
  const e = current();
  if (!e || e.status !== 'ready' || !e.mockOn || !e.mockCanvas) {
    showToast('Add artwork and build a mockup first');
    return null;
  }
  return e;
}

// Render the active mockup to a clean PNG Blob (no selection chrome).
function cleanMockBlob(e) {
  const clean = getCleanMock(e);
  return new Promise((res, rej) => {
    try { clean.toBlob(b => b ? res(b) : rej(new Error('Could not render mockup')), 'image/png'); }
    catch (err) { rej(err); }
  });
}

// Upload the clean mockup PNG and return its displayable URL + keys.
async function uploadCleanMockup(e, namePrefix) {
  const blob = await cleanMockBlob(e);
  const fileName = (namePrefix || 'designer-mockup') + '-' + Date.now() + '.png';
  const fd = new FormData();
  fd.append('file', blob, fileName);
  let resp;
  try {
    resp = await fetchWithTimeout(ART_PROXY_BASE + '/api/files/upload', { method: 'POST', body: fd }, 45000);
  } catch (err) {
    if (err && err.name === 'AbortError') throw new Error('Upload timed out — check your connection and try again');
    throw err;
  }
  const up = await resp.json().catch(() => ({}));
  if (!resp.ok || !up.success || !up.externalKey) {
    throw new Error(up.error || ('Upload failed (' + resp.status + ')'));
  }
  // GET /api/files/:externalKey streams the image directly (no CDN formula).
  return { imageUrl: ART_PROXY_BASE + '/api/files/' + up.externalKey, externalKey: up.externalKey, fileName: up.fileName || fileName };
}

// ── Send to Steve — open the art-submission form pre-filled ────────────────
function buildStevePrefill(e) {
  const seed = window.__artRequestSeed || {};
  let locs;
  try {
    const ents = (typeof mockEntries === 'function' ? mockEntries() : null);
    const list = (ents && ents.length) ? ents : [e];
    locs = list.map(x => ({
      placement: x.printLoc || (sideOf(x) === 'back' ? 'Full Back' : 'Full Front'),
      width: x.printW || ''
    }));
  } catch (_) { locs = [{ placement: e.printLoc || 'Full Front', width: e.printW || '' }]; }

  const isDst = e.kind === 'dst';
  let threadColors = '';
  try { if (isDst && typeof dstThreadColorsOnly === 'function') threadColors = dstThreadColorsOnly(e) || ''; } catch (_) {}
  const garmentColorName = (typeof currentGarmentName !== 'undefined' ? currentGarmentName : '') || seed.garmentName || '';

  const notes = ['Mockup built in the NWCA Shirt Designer (cleaned art attached).'];
  if (garmentColorName) notes.push('Mockup shirt color shown: ' + garmentColorName + '.');
  notes.push('Shown on a PC61 crew tee for placement reference.');

  return {
    company: seed.company || '',
    decoration: isDst ? 'Embroidery' : '',
    threadColors: threadColors,
    exactText: '',
    notes: notes.join(' '),
    artworkStatus: 'Mockup only',
    fileType: 'Customer raster file (PNG / JPG)',
    locations: locs,
    garmentColor: garmentColorName
  };
}

async function openSendToSteve() {
  const e = requireMockup();
  if (!e) return;
  if (typeof GarmentSubmitForm === 'undefined') { showToast('Art form failed to load — refresh and try again'); return; }
  const btn = document.getElementById('sendSteveBtn');
  const orig = btn ? btn.innerHTML : '';
  if (btn) { btn.disabled = true; btn.innerHTML = '⏳ Preparing…'; }
  try {
    const prefill = buildStevePrefill(e);
    const blob = await cleanMockBlob(e);
    prefill.files = [new File([blob], 'designer-mockup-' + Date.now() + '.png', { type: 'image/png' })];
    GarmentSubmitForm.init('steveFormMount', {
      prefill: prefill,
      onSubmitted: function (designId) {
        if (designId) {
          window.__artRequestSeed = window.__artRequestSeed || {};
          window.__artRequestSeed.designId = String(designId);
        }
        showToast(designId ? ('✓ Sent to Steve — request #' + designId + ' created. You can now Send to Customer.') : '✓ Sent to Steve');
        setTimeout(() => dsModalClose('steveModal'), 1400);
      }
    });
    dsModalOpen('steveModal');
  } catch (err) {
    console.error('[openSendToSteve]', err);
    showToast('Could not open the art form: ' + (err && err.message ? err.message : 'unknown error'));
  } finally {
    if (btn) { btn.disabled = false; btn.innerHTML = orig; }
  }
}

// ── Send to Customer — email the mockup + a self-service approval link ──────
function openSendToCustomer() {
  const e = requireMockup();
  if (!e) return;
  const seed = window.__artRequestSeed || {};
  // The approval link points at an art request, so one must exist first.
  if (!seed.designId) {
    showToast('Create the request first with “Send to Steve”, then send to the customer',
      { label: 'Send to Steve', fn: openSendToSteve });
    return;
  }
  const note = document.getElementById('custModalNote');
  if (note) note.textContent = 'Emails an approve / request-changes link for request #' + seed.designId + '. Steve still produces the final production proof.';
  const emailEl = document.getElementById('custEmail');
  if (emailEl && !emailEl.value && seed.contactEmail) emailEl.value = seed.contactEmail;
  dsModalOpen('custModal');
  if (emailEl) emailEl.focus();
}

async function doSendToCustomer() {
  const e = requireMockup();
  if (!e) return;
  const seed = window.__artRequestSeed || {};
  const designId = seed.designId;
  if (!designId) { showToast('No art request to send'); dsModalClose('custModal'); return; }

  const emailEl = document.getElementById('custEmail');
  const nameEl = document.getElementById('custName');
  const msgEl = document.getElementById('custMessage');
  const toEmail = ((emailEl && emailEl.value) || '').trim();
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(toEmail)) { showToast('Enter a valid customer email'); if (emailEl) emailEl.focus(); return; }
  if (typeof emailjs === 'undefined') { showToast('Email service not loaded — refresh and try again'); return; }

  const sendBtn = document.getElementById('custModalSend');
  const orig = sendBtn ? sendBtn.textContent : '';
  if (sendBtn) { sendBtn.disabled = true; sendBtn.textContent = 'Sending…'; }
  try {
    // 1. Upload the current mockup + pin it as the request's Rep_Mockup reference.
    const up = await uploadCleanMockup(e, 'rep-mockup-' + designId);
    fetch(ART_PROXY_BASE + '/api/art-requests/' + encodeURIComponent(designId) + '/fields', {
      method: 'PUT', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ Rep_Mockup: up.imageUrl })
    }).then(r => { if (!r.ok) throw new Error('HTTP ' + r.status); }).catch(err => {
      // The email still carries the URL, so the customer isn't blocked — but the request
      // record didn't get the reference mockup attached. Surface it so the rep can refresh.
      console.error('[doSendToCustomer] Rep_Mockup attach failed:', err);
      showToast("Sent, but couldn't attach the reference mockup to request #" + designId + ' — refresh');
    });

    // 2. Email the customer the mockup + a self-service approval link.
    emailjs.init(EMAILJS_PUBLIC_KEY);
    const repName = (typeof sessionStorage !== 'undefined' && sessionStorage.getItem('nwca_user_name')) || 'Northwest Custom Apparel';
    const repEmail = (typeof sessionStorage !== 'undefined' && sessionStorage.getItem('nwca_user_email')) || 'sales@nwcustomapparel.com';
    await emailjs.send(EMAILJS_SERVICE_ID, 'template_customer_mockup', {
      to_email: toEmail,
      to_name: ((nameEl && nameEl.value) || '').trim() || 'Valued Customer',
      company_name: seed.company || '',
      design_number: designId,
      message: ((msgEl && msgEl.value) || '').trim(),
      mockup_url: up.imageUrl,
      approval_url: SITE_ORIGIN + '/art-request/' + designId + '?view=customer',
      from_name: repName,
      rep_email: repEmail,
      rep_phone: '253-922-5793'
    });

    // 3. Audit note + back-fill the contact email (both fire-and-forget).
    fetch(ART_PROXY_BASE + '/api/art-requests/' + encodeURIComponent(designId) + '/note', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ noteType: 'Customer Share', noteText: 'Mockup shared with customer: ' + toEmail + ' (via Shirt Designer)', noteBy: repEmail })
    }).catch(() => {});
    fetch(ART_PROXY_BASE + '/api/art-requests/' + encodeURIComponent(designId) + '/fields', {
      method: 'PUT', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ Email_Contact: toEmail })
    }).catch(() => {});

    dsModalClose('custModal');
    showToast('✓ Mockup sent to ' + toEmail);
    try { if (window.opener && !window.opener.closed) window.opener.postMessage({ type: 'rep-mockup-saved', designId: designId }, location.origin); } catch (_) {}
  } catch (err) {
    console.error('[doSendToCustomer]', err);
    showToast('Send failed: ' + (err && err.message ? err.message : 'unknown error'));
  } finally {
    if (sendBtn) { sendBtn.disabled = false; sendBtn.textContent = orig; }
  }
}

// ============================================================
//  Phase 3 — Garment style picker
//  "Crew Tee" is the built-in PC61 model photo; the others are SanMar flat
//  laydowns (same-origin assets) fed through the same analyzeShirtImage /
//  recolor pipeline, so they recolor + composite art exactly like the tee.
// ============================================================
const GARMENT_STYLES = [
  { id: 'tee',        name: 'Crew Tee',    builtIn: true },
  { id: 'polo',       name: 'Polo',        front: '/images/garments/polo_front.jpg',       back: '/images/garments/polo_back.jpg' },
  { id: 'hoodie',     name: 'Hoodie',      front: '/images/garments/hoodie_front.jpg',     back: '/images/garments/hoodie_back.jpg' },
  { id: 'longsleeve', name: 'Long Sleeve', front: '/images/garments/longsleeve_front.jpg', back: '/images/garments/longsleeve_back.jpg' },
  { id: 'ladies',     name: 'Ladies Tee',  front: '/images/garments/ladies_front.jpg',     back: '/images/garments/ladies_back.jpg' },
];
let currentGarmentStyle = 'tee';

function loadGarmentImage(url) {
  return new Promise((res, rej) => {
    const im = new Image();
    im.crossOrigin = 'anonymous';                 // same-origin, but keeps the canvas un-tainted
    im.onload = () => res(im);
    im.onerror = () => rej(new Error('Could not load ' + url));
    im.src = url;
  });
}

async function setGarmentStyle(styleId) {
  const st = GARMENT_STYLES.find(s => s.id === styleId);
  if (!st) return;
  currentGarmentStyle = styleId;

  // Back to the built-in crew-tee model photo.
  if (st.builtIn) {
    PHOTO.state = 'idle';
    PHOTO.frames = [];
    PHOTO.viewCache.clear();
    initPhotoMock();                              // async; PHOTO.pending drives the rebuild
    const e = current();
    if (e && e.status === 'ready') { e._customerForceMock = true; rebuildMockup(e); refreshStage(e); renderInfo(e); }
    showToast('Crew tee');
    return;
  }

  showToast('Loading ' + st.name + '…');
  try {
    const loaded = [];
    for (const [url, angle] of [[st.front, 0], [st.back, 180]]) {
      const img = await loadGarmentImage(url);
      // Staleness guard: if the user picked a different garment while this image
      // was decoding, abandon this load so a slow Polo request can't clobber the
      // Hoodie the user is now on. currentGarmentStyle is the intended selection.
      if (currentGarmentStyle !== styleId) return;
      const fr = analyzeShirtImage(img);          // chroma-key + shade/mask, same as the tee
      if (!fr) continue;
      fr.angle = angle;
      loaded.push(fr);
    }
    // Re-check after all awaits before committing frames to PHOTO (the shared,
    // globally-read mockup state) — a switch during the last decode still races here.
    if (currentGarmentStyle !== styleId) return;
    if (!loaded.length) { showToast('Could not read ' + st.name + ' artwork'); return; }
    loaded.sort((a, b) => a.angle - b.angle);
    PHOTO.frames = loaded;
    PHOTO.idx = 0; PHOTO.pos = 0;
    PHOTO.viewCache.clear();
    PHOTO.state = 'ready';
    const e = current();
    if (e && e.status === 'ready') {
      if (!e.mockOn) toggleMockup();
      else { rebuildMockup(e); refreshStage(e); renderInfo(e); }
    }
    showToast(st.name + ' loaded');
  } catch (err) {
    console.error('[setGarmentStyle]', err);
    showToast('Could not load ' + st.name + ' — staying on the current garment');
  }
}

// Wire the new buttons + modals (addEventListener, not inline onclick).
(function wireSendActions() {
  const on = (id, fn) => { const el = document.getElementById(id); if (el) el.addEventListener('click', fn); };
  on('sendSteveBtn', openSendToSteve);
  on('sendCustomerBtn', openSendToCustomer);
  on('steveModalClose', () => dsModalClose('steveModal'));
  on('custModalClose', () => dsModalClose('custModal'));
  on('custModalCancel', () => dsModalClose('custModal'));
  on('custModalSend', doSendToCustomer);
  ['steveModal', 'custModal'].forEach(id => {
    const m = document.getElementById(id);
    if (m) m.addEventListener('click', (ev) => { if (ev.target === m) dsModalClose(id); });
  });
  document.addEventListener('keydown', (ev) => { if (ev.key === 'Escape') { dsModalClose('steveModal'); dsModalClose('custModal'); } });

  // Garment-style picker: populate from GARMENT_STYLES + swap the mockup garment.
  const gsel = document.getElementById('garmentStyleSelect');
  if (gsel) {
    gsel.innerHTML = GARMENT_STYLES.map(s => '<option value="' + s.id + '">' + escapeHtml(s.name) + '</option>').join('');
    gsel.value = currentGarmentStyle;
    gsel.addEventListener('change', () => setGarmentStyle(gsel.value));
  }
})();

// ============================================================
//  Text tool — add editable text as a first-class art entry.
//  A text entry is kind:'canvas' (so it flows through placement,
//  the mockup compositing, the proof, and Save/Send unchanged)
//  with an attached .textModel describing how to render it.
// ============================================================
const TEXT_FONT_GROUPS = [
  { group: 'Athletic / Block', fonts: ['Anton', 'Bebas Neue', 'Oswald', 'Archivo Black', 'Alfa Slab One', 'Russo One', 'Staatliches', 'Graduate', 'Black Ops One', 'Bungee'] },
  { group: 'Sans / Serif', fonts: ['Montserrat', 'Roboto Slab', 'Playfair Display', 'Merriweather'] },
  { group: 'Script / Handwritten', fonts: ['Pacifico', 'Dancing Script', 'Great Vibes', 'Lobster', 'Satisfy', 'Caveat', 'Shadows Into Light'] },
  { group: 'Fun / Display', fonts: ['Permanent Marker', 'Bangers', 'Fredoka'] }
];
const TEXT_RENDER_PX = 220;
const _loadedTextFonts = new Set();

function ensureTextFont(m) {
  var fam = m.font || 'Anton';
  var spec = (m.italic ? 'italic ' : '') + (m.weight || 700) + ' ' + TEXT_RENDER_PX + 'px "' + fam + '"';
  if (_loadedTextFonts.has(spec)) return Promise.resolve();
  if (!document.fonts || !document.fonts.load) return Promise.resolve();
  return document.fonts.load(spec).then(function () { _loadedTextFonts.add(spec); }).catch(function () {});
}
// Pure text/contrast math lives in shared_components/js/garment-text-engine.js
// (loaded before this script) so it can be unit-tested. These thin wrappers keep
// the existing call sites working.
function _txtCase(t, mode) { return GarmentTextEngine.txtCase(t, mode); }
function _txtFont(m) { return (m.italic ? 'italic ' : '') + (m.weight || 700) + ' ' + TEXT_RENDER_PX + 'px "' + (m.font || 'Anton') + '", sans-serif'; }

function renderTextCanvas(model) {
  var m = model || {};
  var raw = (m.text != null ? String(m.text) : '') || ' ';
  var text = _txtCase(raw, m.caseMode);
  var s = {
    fill: m.fill || '#1c2841',
    strokeOn: !!m.strokeOn,
    stroke: m.stroke || '#ffffff',
    strokeW: m.strokeOn ? Math.max(0, +m.strokeW || 0) : 0,
    tracking: +m.tracking || 0,
    lineHeight: +m.lineHeight || 1.1,
    align: m.align || 'center',
    bend: Math.max(-1, Math.min(1, (+m.arc || 0) / 100))
  };
  var out = (Math.abs(s.bend) < 0.06)
    ? _txtStraight(text, m, s)
    : _txtArc(text.replace(/\n/g, ' '), m, s);
  var rot = +m.rotation || 0;
  if (rot) out = _txtRotate(out, rot);
  try { return trimTransparentArtCanvas(out); } catch (e) { return out; }
}
function _txtStraight(text, m, s) {
  var px = TEXT_RENDER_PX, lines = text.split('\n');
  var meas = document.createElement('canvas').getContext('2d');
  meas.font = _txtFont(m);
  if ('letterSpacing' in meas) meas.letterSpacing = s.tracking + 'px';
  var maxW = 1;
  lines.forEach(function (ln) { var w = meas.measureText(ln || ' ').width; if (w > maxW) maxW = w; });
  var lineH = px * s.lineHeight;
  var pad = s.strokeW * 1.6 + px * 0.45;
  var W = Math.ceil(maxW + 2 * pad), H = Math.ceil(lines.length * lineH + 2 * pad);
  var c = document.createElement('canvas'); c.width = W; c.height = H;
  var ctx = c.getContext('2d');
  ctx.font = _txtFont(m);
  if ('letterSpacing' in ctx) ctx.letterSpacing = s.tracking + 'px';
  ctx.textBaseline = 'middle'; ctx.lineJoin = 'round'; ctx.miterLimit = 2;
  for (var i = 0; i < lines.length; i++) {
    var ln = lines[i], x = W / 2; ctx.textAlign = 'center';
    if (s.align === 'left') { x = pad; ctx.textAlign = 'left'; }
    else if (s.align === 'right') { x = W - pad; ctx.textAlign = 'right'; }
    var y = pad + lineH * (i + 0.5);
    if (s.strokeOn && s.strokeW > 0) { ctx.strokeStyle = s.stroke; ctx.lineWidth = s.strokeW; ctx.strokeText(ln, x, y); }
    ctx.fillStyle = s.fill; ctx.fillText(ln, x, y);
  }
  return c;
}
function _txtArc(text, m, s) {
  var px = TEXT_RENDER_PX;
  var meas = document.createElement('canvas').getContext('2d');
  meas.font = _txtFont(m);
  var chars = Array.from(text);
  var widths = chars.map(function (ch) { return meas.measureText(ch).width + s.tracking; });
  // Pure layout geometry from the engine module (unit-tested separately).
  var lay = GarmentTextEngine.arcLayout(widths, s.bend, px, s.strokeW);
  var c = document.createElement('canvas'); c.width = lay.W; c.height = lay.H;
  var ctx = c.getContext('2d');
  ctx.font = _txtFont(m); ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.lineJoin = 'round';
  for (var i = 0; i < chars.length; i++) {
    var pc = lay.perChar[i];
    ctx.save(); ctx.translate(pc.x, pc.y); ctx.rotate(pc.rot);
    if (s.strokeOn && s.strokeW > 0) { ctx.strokeStyle = s.stroke; ctx.lineWidth = s.strokeW; ctx.strokeText(chars[i], 0, 0); }
    ctx.fillStyle = s.fill; ctx.fillText(chars[i], 0, 0);
    ctx.restore();
  }
  return c;
}
function _txtRotate(src, deg) {
  var b = GarmentTextEngine.rotatedBounds(src.width, src.height, deg);
  var c = document.createElement('canvas'); c.width = b.W; c.height = b.H;
  var ctx = c.getContext('2d');
  ctx.translate(b.W / 2, b.H / 2); ctx.rotate(deg * Math.PI / 180); ctx.drawImage(src, -src.width / 2, -src.height / 2);
  return c;
}

function _defaultTextModel() { return GarmentTextEngine.defaultTextModel(); }
function addTextEntry() {
  const model = _defaultTextModel();
  const entry = {
    id: nextId++, kind: 'canvas', ext: 'text', name: 'Text', size: 0,
    status: 'ready', textModel: model, canvas: renderTextCanvas(model),
    info: {}, view: { z: 1, tx: 0, ty: 0, fitted: false }
  };
  entries.push(entry);
  addFileItem(entry); refreshFileItem(entry); makeThumb(entry, entry.canvas);
  try { analyzeEntry(entry); } catch (e) { /* non-fatal */ }
  $('dropzone').classList.add('hidden');
  $('toolbar').classList.add('visible');
  updateSidebarVisibility();
  applyRecommendedPlacement(entry, 'Full Front', true);
  entry._customerForceMock = true;
  selectEntry(entry.id);
  if (!entry.mockOn) toggleMockup(); else { rebuildMockup(entry); refreshStage(entry); renderInfo(entry); }
  ensureTextFont(model).then(function () { applyTextEntry(entry); });
  openTextPanel(entry);
  updateEasyStatus('Editing text — type, then pick a font, color, and curve');
}
function applyTextEntry(entry) {
  ensureTextFont(entry.textModel).then(function () {
    entry.canvas = renderTextCanvas(entry.textModel);
    entry._trimmedArt = null;
    // Bump eraseN so mockFingerprint() changes — the text content changed even
    // when placement didn't, so the cached mockup composite must be rebuilt.
    entry.eraseN = (entry.eraseN || 0) + 1;
    var first = (entry.textModel.text || '').split('\n')[0].slice(0, 22) || 'Text';
    entry.name = 'Text: ' + first;
    var fi = $('fitem-' + entry.id);
    if (fi) { var el = fi.querySelector('.fname'); if (el) { el.textContent = entry.name; el.title = entry.name; } }
    makeThumb(entry, entry.canvas);
    if (entry.id === activeId) redrawDesignerEntry(entry);
    try { maybeWarnLowContrast(entry); } catch (e) {}
  });
}
function txtActiveEntry() { const e = current(); return (e && e.textModel) ? e : null; }
function txtSet(field, value) { const e = txtActiveEntry(); if (!e) return; e.textModel[field] = value; applyTextEntry(e); syncTextPanelControls(e); }

function deleteTextEntry() {
  const e = txtActiveEntry(); if (!e) return;
  const idx = entries.findIndex(x => x.id === e.id);
  if (idx > -1) entries.splice(idx, 1);
  const fi = $('fitem-' + e.id); if (fi) fi.remove();
  closeTextPanel();
  updateSidebarVisibility();
  const next = entries[entries.length - 1];
  if (next) { selectEntry(next.id); if (next.mockOn || next._customerForceMock) rebuildMockup(next); refreshStage(next); }
  else { $('dropzone').classList.remove('hidden'); $('toolbar').classList.remove('visible'); holder.innerHTML = ''; activeId = null; }
  showToast('Text removed');
}

// ── Text editor panel ─────────────────────────────────────────────────────
function openTextPanel(entry) {
  const p = $('textPanel'); if (!p) return;
  p.classList.add('open');
  syncTextPanelControls(entry);
  const ta = $('txt-text'); if (ta) { ta.focus(); ta.select(); }
}
function closeTextPanel() { const p = $('textPanel'); if (p) p.classList.remove('open'); }
function syncTextPanel(entry) {
  if (entry && entry.textModel) openTextPanel(entry); else closeTextPanel();
}
function _segActive(sel, attr, val) {
  document.querySelectorAll(sel).forEach(function (b) { b.classList.toggle('on', b.getAttribute(attr) === val); });
}
function syncTextPanelControls(e) {
  if (!e || !e.textModel) return;
  const m = e.textModel, set = function (id, v) { const el = $(id); if (el) el.value = v; };
  set('txt-text', m.text);
  set('txt-font', m.font);
  set('txt-fill', m.fill);
  set('txt-stroke', m.stroke);
  set('txt-strokeW', m.strokeW);
  set('txt-tracking', m.tracking);
  set('txt-lh', m.lineHeight);
  set('txt-arc', m.arc);
  set('txt-rot', m.rotation);
  const so = $('txt-stroke-on'); if (so) so.checked = !!m.strokeOn;
  const bold = $('txt-bold'); if (bold) bold.classList.toggle('on', (m.weight || 700) >= 700);
  const ital = $('txt-italic'); if (ital) ital.classList.toggle('on', !!m.italic);
  _segActive('.tp-seg-btn[data-align]', 'data-align', m.align || 'center');
  _segActive('.tp-seg-btn[data-case]', 'data-case', m.caseMode || 'none');
  const lab = function (id, v) { const el = $(id); if (el) el.textContent = v; };
  lab('txt-tracking-v', m.tracking);
  lab('txt-lh-v', (+m.lineHeight).toFixed(2));
  lab('txt-arc-v', m.arc);
  lab('txt-rot-v', m.rotation + '°');
  const fontSel = $('txt-font'); if (fontSel) fontSel.style.fontFamily = '"' + m.font + '"';
}

(function wireTextTool() {
  // populate font select
  const sel = $('txt-font');
  if (sel) {
    TEXT_FONT_GROUPS.forEach(function (g) {
      const og = document.createElement('optgroup'); og.label = g.group;
      g.fonts.forEach(function (f) {
        const o = document.createElement('option'); o.value = f; o.textContent = f; o.style.fontFamily = '"' + f + '"';
        og.appendChild(o);
      });
      sel.appendChild(og);
    });
  }
  const on = function (id, ev, fn) { const el = $(id); if (el) el.addEventListener(ev, fn); };
  on('addTextBtn', 'click', addTextEntry);
  on('txt-text', 'input', function () { txtSet('text', this.value); });
  on('txt-font', 'change', function () { txtSet('font', this.value); });
  on('txt-fill', 'input', function () { txtSet('fill', this.value); });
  on('txt-stroke', 'input', function () { txtSet('stroke', this.value); });
  on('txt-stroke-on', 'change', function () { txtSet('strokeOn', this.checked); });
  on('txt-strokeW', 'input', function () { txtSet('strokeW', +this.value); });
  on('txt-tracking', 'input', function () { txtSet('tracking', +this.value); });
  on('txt-lh', 'input', function () { txtSet('lineHeight', +this.value); });
  on('txt-arc', 'input', function () { txtSet('arc', +this.value); });
  on('txt-rot', 'input', function () { txtSet('rotation', +this.value); });
  on('txt-bold', 'click', function () { const e = txtActiveEntry(); if (e) txtSet('weight', (e.textModel.weight >= 700) ? 400 : 700); });
  on('txt-italic', 'click', function () { const e = txtActiveEntry(); if (e) txtSet('italic', !e.textModel.italic); });
  document.querySelectorAll('.tp-seg-btn[data-align]').forEach(function (b) { b.addEventListener('click', function () { txtSet('align', b.getAttribute('data-align')); }); });
  document.querySelectorAll('.tp-seg-btn[data-case]').forEach(function (b) { b.addEventListener('click', function () { txtSet('caseMode', b.getAttribute('data-case')); }); });
  on('tpClose', 'click', closeTextPanel);
  on('tpDone', 'click', closeTextPanel);
  on('tpDelete', 'click', deleteTextEntry);
})();

